class Codec:
    def serialize(self, root):
        def dfs(n):
            if not n: return "null,"
            return str(n.val)+","+dfs(n.left)+dfs(n.right)
        return dfs(root)
    def deserialize(self, data):
        it = iter(data.split(","))
        def build():
            v = next(it)
            if v == "null": return None
            node = TreeNode(int(v))
            node.left = build(); node.right = build()
            return node
        return build()

